-- 검증
DO $$
DECLARE missing INT;
BEGIN
  SELECT COUNT(*) INTO missing FROM quests
  WHERE mission_code IS NULL
    AND NOT (COALESCE(title_ko,'') LIKE '%[DBG]%'
          OR COALESCE(title_en,'') LIKE '%[DBG]%');
  IF missing > 0 THEN
    RAISE EXCEPTION '% non-DBG quests have NULL mission_code', missing;
  END IF;
END $$;

COMMIT;
